import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"70. Long Service Leave","description":"","frontmatter":{"title":"70. Long Service Leave","eba":"Nurses and Midwives 2024-2028","topics":["leave","long-service-leave","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/70-long-service-leave.md","filePath":"ebas/nurses-midwives/leave/70-long-service-leave.md"}'),a={name:"ebas/nurses-midwives/leave/70-long-service-leave.md"};function i(s,e,l,p,c,m){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_70-long-service-leave" tabindex="-1">70. Long Service Leave <a class="header-anchor" href="#_70-long-service-leave" aria-label="Permalink to &quot;70. Long Service Leave&quot;">​</a></h1><p>Part 1 - General</p><p><strong>70.1</strong> Scope This clause is split into 4 parts:</p><p><strong>(a)</strong> Part 1 (Clauses 70.1 - 70.2) explains the scope of this clause and includes defined terms used across each Part;</p><p><strong>(b)</strong> Part 2 (Clauses 70.3 - 70.11) sets out the long service leave entitlement of Employees employed on a full-time or part-time basis, or who are employed as Enrolled Nurses at the time they take a period of long service leave or their employment ceases;</p><p><strong>(c)</strong> Part 3 (Clauses 70.12 - 70.19) sets out the long service leave entitlement of Employees employed as casual Registered Nurses or casual Registered Midwives at the time they take a period of long service leave or their employment ceases; and</p><p><strong>(d)</strong> Part 4 (Clauses 70.20 - 70.25) contains a series of common provisions that apply in respect of all Employees.</p><p><strong>70.2</strong> Definitions</p><p>The following meanings shall apply to the terms referred to below for the purposes of this clause unless a contrary intention is apparent:</p><p><strong>(a)</strong> Award-entitled Employee means:</p><p><strong>(i)</strong> a full-time or part-time Registered Nurse;</p><p><strong>(ii)</strong> a full-time or part-time Registered Midwife; or</p><p><strong>(iii)</strong> a full-time, part-time or casual Enrolled Nurse.</p><p><strong>(b)</strong> Casual Registered Nurse or Casual Registered Midwife means a Registered Nurse or Registered Midwife employed on a casual basis in accordance with <a href="/eba/ebas/doctors-in-training/doctor-employment/19-casual-employment.html">clause 19</a> (Casual Employment).</p><p><strong>(c)</strong> Institution means any Employer, or a hospital or benevolent home, community health centre, Society or Association:</p><p><strong>(i)</strong> named in <a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> of this Agreement;</p><p><strong>(ii)</strong> that was registered and subsidised pursuant to the Hospital and Charities Act 1958 (Vic) or the Health Services Act 1988 (Vic);</p><p><strong>(iii)</strong> the Cancer Institute constituted under the Cancer Act 1958 (Vic);</p><p><strong>(iv)</strong> the Fairfield Hospital Board;</p><p><strong>(v)</strong> the Victorian Bush Nursing Association (Inc.); or</p><p><strong>(vi)</strong> a Bush Nursing institution.</p><p><strong>(d)</strong> Full-time or part-time Registered Nurse or Registered Midwife means a person classified or employed as such at the time they apply for or commence long service leave.</p><p><strong>(e)</strong> LSL Act means the Long Service Leave Act 2018 (Vic).</p><p><strong>(f)</strong> Month means a calendar month.</p><p><strong>(g)</strong> Pay means:</p><p><strong>(i)</strong> for an Award-entitled Employee (subject to subclause 70.2(g)(ii) for part-time Employees), remuneration for an Employee’s normal weekly hours of work calculated at the Employee’s ordinary time rate of pay provided in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, at the time the leave is taken or (if they die before the completion of leave so taken) as at the time of their death, and will include the amount of any increase to the Employee’s ordinary time rate of pay which occurred during the period of leave;</p><p><strong>(ii)</strong> for a part-time Employee whose ordinary hours of work fluctuate because the Employee works additional ordinary shifts (but excluding a permanent variation), the greater of:</p><p><strong>(A)</strong> the Employee&#39;s ordinary weekly hours at the time long service leave is taken; or</p><p><strong>(B)</strong> the average weekly ordinary hours the Employee worked over the preceding 12 months; and</p><p><strong>(iii)</strong> for a casual Enrolled Nurse, the remuneration for the Employee’s normal weekly hours of work at their ordinary pay calculated in accordance with sections 15 and 16 of the LSL Act.</p><p><strong>(h)</strong> Service means employment with an Employer, Institution or Statutory Body.</p><p><strong>(i)</strong> Statutory Body means the Hospital and Charities Commission of Victoria, a public entity within the meaning of the Public Administration Act 2004 (Vic), the Department of Education and Early Childhood Development, the Health Commission of Victoria, the DOH and the Nurses Board of Victoria.</p><p><strong>(j)</strong> Transfer of business occurs in the circumstances described at section 311 of the Act.</p><p>Part 2 - Long service leave for Award-entitled Employees</p><p><strong>70.3</strong> Application of Part 2 This part (clauses 70.3 - 70.11) applies to Award-entitled Employees only.</p><p><strong>70.4</strong> Entitlement</p><p><strong>(a)</strong> Subject to clause 70.6, Award-entitled Employees are entitled to:</p><p><strong>(i)</strong> six months&#39; long service leave with Pay on completion of fifteen years of Continuous Service; and</p><p><strong>(ii)</strong> thereafter an additional two months&#39; long service leave with Pay on completion of each additional five years of Continuous Service.</p><p><strong>(b)</strong> Subject to subclause 70.7(c), the entitlement under subclause 70.4(a)(i) may be taken in advance on a pro rata basis if the Employee has accrued at least 7 years&#39; Continuous Service.</p><p><strong>70.5</strong> Calculating Continuous Service</p><p><strong>(a)</strong> Definitions:</p><p><strong>(i)</strong> Continuous Service means continuous Service with the same Employer plus any prior continuous Service of six months or more with one or more Institutions or Statutory Bodies directly associated with such Institutions.</p><p><strong>(ii)</strong> Continuous Casual Employment means, for the purpose of subclause 70.5(b), a period or periods of casual employment with the same Employer that are taken to be continuous, because one of the following applies:</p><p><strong>(A)</strong> the period starting at the end of a particular instance of employment and ending at the start of another particular instance of employment did not exceed either the Allowable Period of Absence, or 12 weeks (whichever is greater);</p><p><strong>(B)</strong> the Employee had been employed by an Employer on a regular and systematic basis and the Employee had a reasonable expectation of being re-engaged by the same Employer;</p><p><strong>(C)</strong> the gap between engagements was due to the terms of engagement of the casual Employee;</p><p><strong>(D)</strong> the gap between engagements was caused by seasonal factors; or</p><p><strong>(E)</strong> the Employee and Employer agreed, before the start of an absence, to treat the employment as continuous despite the absence.</p><p><strong>(b)</strong> Periods that count towards Continuous Service</p><p>Service or prior service during the following periods will be deemed to be continuous and will count as Continuous Service for the purpose of subclause (a):</p><p><strong>(i)</strong> an absence from work on any form of paid leave (e.g. annual leave, personal leave, long service leave and paid parental leave);</p><p><strong>(ii)</strong> any interruption or ending of employment by the Employer if made with the intention of avoiding obligations in respect of long service leave or annual leave;</p><p><strong>(iii)</strong> any absence on account of illness or injury arising out of or in the course of the employment for a period during which an Award-entitled Employee is receiving compensation make-up pay under <a href="/eba/ebas/nurses-midwives/wages/29-compensation-make-up-pay.html">clause 29</a> (Compensation Make-Up Pay);</p><p><strong>(iv)</strong> any absence from employment on defence service in accordance with section 8 of the Defence Reserve Service (Protection) Act 2001 (Cth);</p><p><strong>(v)</strong> a period of absence on community service leave under the Act;</p><p><strong>(vi)</strong> in the case of unpaid absences not otherwise referenced in this subclause:</p><p><strong>(A)</strong> any unpaid leave that is authorised in advance in writing by the Employer to count as service;</p><p><strong>(B)</strong> any unpaid parental leave taken between 1 November 2018 and 30 June 2020 that counts as service because of an application made by the Employee under clause 70.11 of the 2020 Agreement; or</p><p><strong>(C)</strong> up to (and including) 30 June 2020, any unpaid absence from work of not more than fourteen days in any year on account of illness or injury; or</p><p><strong>(D)</strong> on and from 1 July 2020:</p><p>1) any period of unpaid leave taken on account of illness or injury;</p><p>2) a period of parental leave, including parental leave that is extended under <a href="/eba/ebas/nurses-midwives/leave/68-parental-leave.html">clause 68.12</a>; and</p><p>3) the first 52 weeks of any other type of unpaid leave not specifically referenced in this subclause 70.5(b)(vi);</p><p><strong>(vii)</strong> periods of Continuous Casual Employment with the current Employer (whether or not in a role covered by this Agreement);</p><p><strong>(viii)</strong> prior Continuous Casual Employment of six months or more that was with one or more Institutions or Statutory Bodies directly associated with such Institutions (subject to clauses 70.8(c) and 70.24), provided that in the case of a casual Registered Nurse or casual Registered Midwife, portability of such Service will only apply if the Employee was an Award-entitled Employee at the time their employment with the other Institution or associated Statutory Body was terminated; and</p><p><strong>(ix)</strong> prior employment with a public health service in another State or Territory or Council in Victoria as defined in the Local Government Act 2020 (Vic), as follows:</p><p><strong>(A)</strong> such employment may only be recognised on the first occasion that the Employee commences employment with an Employer after 24 June 2024;</p><p><strong>(B)</strong> such employment will only be recognised in respect of the period of employment that was recognised as continuous service for the purpose of the Employee&#39;s long service leave entitlement with the interstate public health service or Council (as applicable); and</p><p><strong>(C)</strong> such employment will only be recognised where the break between ceasing employment with the interstate public health service, and commencing employment with the Employer, is no more than the greater of two Months or the Allowable Period of Absence,</p><p>save that if long service leave was already taken or paid in lieu in respect of any such period, no further benefit to long service leave will arise in respect of that period.</p><p><strong>(c)</strong> Periods that do not break Continuous Service, but do not count towards Continuous Service</p><p>Unless otherwise agreed in writing in advance between the Employer and Employee, the following periods do not break Continuous Service but do not count towards an Award-entitled Employee&#39;s Continuous Service for the purpose of calculating the Employee&#39;s long service leave entitlement:</p><p><strong>(i)</strong> any authorised period of unpaid leave as an Award-entitled Employee not referred to in subclause 70.5(b);</p><p><strong>(ii)</strong> subject to the requirements of the Act, any interruption arising directly or indirectly from an industrial dispute;</p><p><strong>(iii)</strong> any period between the engagement with one Institution or Statutory Body and another provided it is less than the Allowable Period of Absence from employment (as defined above at subclause 4.1(f));</p><p><strong>(iv)</strong> the dismissal of an Employee if the Employee is re-employed by the same Employer within a period not exceeding two months from the date of such dismissal;</p><p><strong>(v)</strong> any absence on account of injury arising out of or in the course of their employment not covered by a period in which the Award-entitled Employee is receiving compensation make-up pay or other paid leave;</p><p><strong>(vi)</strong> any unpaid absence of not more than 24 months for the sole purpose of an Award-entitled Employee undertaking a course of study related to nursing or midwifery where the written approval of the Employer is given;</p><p><strong>(vii)</strong> any absence from work of a female Award-entitled Employee for a period not exceeding 12 months in respect of any pregnancy not covered by subclauses 70.5(b)(i) or (vi); or</p><p><strong>(viii)</strong> the break between periods of employment that is referenced above at subclause 70.5(b)(ix)(C).</p><p><strong>70.6</strong> Accrual rate for mixed service (Registered Nurses and Registered Midwives)</p><p>Where a Registered Nurse or Registered Midwife has Continuous Service that includes a mixture of full-time/part-time service, on the one hand, and eligible casual service (i.e. service within the meaning of subclause 70.5(b)(viii)) as a Registered Nurse or Midwife (or service within the meaning of subclause 70.5(b)(vii)) on the other, the accrual rates for their long service leave entitlement will correspond to the relative periods of each type of the service. That is:</p><p><strong>(a)</strong> the periods of full-time/part-time service will accrue at the rate of 1.733 weeks&#39; per year of eligible service; and</p><p><strong>(b)</strong> the periods of eligible casual service will accrue at the rate of 0.8667 weeks per year of eligible service.</p><p>Example:</p><p>Period Nature of Accrual Rate Duration Total Comment Employment for LSL of Period Amount of or Leave Purposes LSL (Weeks Per Accrued Year of for Period Service) (in Weeks) 1/1/2008 – Casual 0.8667 3 years 2.6001 31/12/2010 (13 weeks (3 years x after 15 years’ 0.8667) service) 1/1/2011 – Full-time 1.733 5 years 8.665 (5 years 31/12/2015 (26 weeks x 1.733) after 15 years’ service 1/1/2016 – Unpaid Parental NIL 1 year NIL No accrual of 31/12/2016 Leave LSL during unpaid Parental Leave before November 1/1/2017 – Part-time 1.733 4 years 6.932 (4 years 31/12/2020 x 1.733) 1/1/2020 – Unpaid Parental 1.733 2 years 3.466 If application 31/12/2021 Leave made under clause 70.11 for recognition of the period between 1 Jan 2020 - 30 June 2020 Total 21.6631 weeks of accrued LSL</p><p><strong>70.7</strong> Taking of leave</p><p><strong>(a)</strong> When leave is to be taken</p><p>Long service leave will be granted by the Employer within six months from the date of the entitlement under subclause 70.4(a) save that:</p><p><strong>(i)</strong> long service leave may be postponed to a mutually agreeable date;</p><p><strong>(ii)</strong> if agreement cannot be reached, the date will be determined by a member of the Fair Work Commission provided that such a determination will not require leave to commence before six months from the date of such determination; and</p><p><strong>(iii)</strong> leave the subject of approval or grant under subclause 70.7(c) shall be taken in accordance with the terms of the application or agreement.</p><p><strong>(b)</strong> How leave is to be taken</p><p>Long service leave will be taken:</p><p><strong>(i)</strong> in one period or more periods, with each period being not less than 1 day; or</p><p><strong>(ii)</strong> where it is taken as part of a transition to retirement arrangement, any other way agreed upon by the Employer and Employee.</p><p><strong>(c)</strong> Long service leave in advance</p><p><strong>(i)</strong> If an Award-entitled Employee has completed ten years&#39; Continuous Service, an Employer may, by agreement with the Employee, grant long service leave in advance on a pro rata basis.</p><p><strong>(ii)</strong> Supplementary to subclause 70.7(c)(i), if an Award-entitled Employee requests to take long service leave on a pro rata basis under subclause 70.4(b), the Employer must grant the Employee&#39;s request to take long service leave as soon as practicable after receiving the request unless the Employer has reasonable business grounds for refusing the request.</p><p><strong>(d)</strong> Flexible taking of leave: double leave at half pay</p><p><strong>(i)</strong> An Employer may approve an application by an Award-entitled Employee to take double the period of long service leave at half pay.</p><p><strong>(ii)</strong> Employees should seek independent advice regarding the taxation and superannuation implications of seeking payment under this subclause 70.7(d). The Employer will not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>(iii)</strong> The Employer, if requested by the Employee, will provide information as to the amount of tax the Employer intends to deduct where payment of long service leave is sought under subclause 70.7(d)(i).</p><p><strong>(iv)</strong> If granting the request under this subclause would result in an additional cost to the Employer, the Employer may refuse the Employee&#39;s request.</p><p><strong>(v)</strong> Flexible taking of long service leave does not affect an Employee&#39;s period of continuous service recognised. For example, an Employee taking 12 months of long service leave at half pay will, for the purpose of calculating continuous service, have six months of continuous service recognised.</p><p><strong>70.8</strong> Payment on termination of employment</p><p><strong>(a)</strong> Interpretation</p><p>For the purposes of this clause 70.8, termination of employment has its ordinary meaning, provided that:</p><p><strong>(i)</strong> it is taken to occur upon conversion from full-time or part-time employment to casual employment; and</p><p><strong>(ii)</strong> it is not taken to occur at the cessation of each shift as a casual Enrolled Nurse.</p><p><strong>(b)</strong> Basic entitlement at termination of employment</p><p>Except where an election is made under subclause 70.8(c) below, an Employee with an entitlement to long service leave under clause 70.4 is entitled to payment in lieu of untaken long service leave upon termination of employment, calculated at the applicable rate, namely:</p><p><strong>(i)</strong> for full-time and part-time Registered Nurses and Registered Midwives who derive a long service leave entitlement at the mixed accrual rates referred to in clause 70.6 above, at those rates (provided that the termination occurred on or after 23 December 2016); or</p><p><strong>(ii)</strong> otherwise, one thirtieth of the period of continuous service.</p><p><strong>(c)</strong> Election for payment of entitlement or transfer of entitlement at termination</p><p><strong>(i)</strong> An Award-entitled Employee who has an entitlement to take long service leave on a pro rata basis under subclause 70.4(b) (who therefore has less than 15 years&#39; continuous service) and who intends to be re-employed by another Institution or Statutory Body may:</p><p><strong>(A)</strong> request in writing that payment for accrued long service leave be deferred until after the Employee’s Allowable Period of Absence (as defined above) has expired; and</p><p><strong>(B)</strong> where the Employee notifies the initial Employer in writing within the Allowable Period of Absence that the Employee has been employed by another Institution or Statutory Body, and the re-employment meets the criteria set out in in subclause 70.8(c)(iii) below, the initial Employer is no longer required to make payment to the Employee in respect of such service.</p><p><strong>(ii)</strong> Where the notice referred to at subclause 70.8(c)(i)(B) is not provided prior to or within the Allowable Period of Absence, the Employer will, upon the expiration of the Allowable Period of Absence, make payment in lieu of long service leave as per subclause 70.8(b).</p><p><strong>(iii)</strong> For the purposes of this subclause, re-employment by another Institution or Statutory Body means employment as an Award-entitled Employee.</p><p><strong>(iv)</strong> For the removal of doubt, an Award-entitled Employee who has an entitlement to take long service leave under subclause 70.4(a) may not make an election under this clause in respect of that entitlement.</p><p><strong>(d)</strong> Payment in lieu of long service leave on the death of an Employee</p><p>Where an Employee who has an entitlement to long service leave (or pro rata long service leave) under clause 70.4 dies while still in the employ of the Employer, payment in lieu of long service leave will be made to the Employee’s personal representative equal to that in subclause 70.8(b) above.</p><p><strong>70.9</strong> Public holidays and Accrued Days Off Long service leave is inclusive of Public Holidays and Accrued Days Off. See also clauses 56 (Public Holidays) and 43 (Accrued Days Off).</p><p><strong>70.10</strong> No entitlement arising for periods of leave already taken For the removal of doubt, where an Employee makes an election under subclause 70.8(c) such that their previous service is recognised by the new Employer, the Employee’s previous employer is no longer liable to make any payment in lieu of that Employee’s service.</p><p><strong>70.11</strong> Not used</p><p>Part 3 - Long service leave for Casual Registered Nurses and Casual Registered Midwives</p><p><strong>70.12</strong> Application of Part 3 A Casual Registered Nurse or Casual Registered Midwife shall be entitled to long service leave with ordinary pay in accordance with this Part 3 (clauses 70.12 - 70.19).</p><p><strong>70.13</strong> Interpretation</p><p>For the purposes of this Part 3:</p><p><strong>(a)</strong> One Employer has the meaning given in section 11 of the LSL Act;</p><p><strong>(b)</strong> Continuous employment has the meaning given in sections 12-14 and 57 of the LSL Act;</p><p><strong>(c)</strong> Ordinary pay has the meanings given in sections 15, 17 and 21 of the LSL Act; and</p><p><strong>(d)</strong> Normal weekly hours has the meaning given in sections 16 and 17 of the LSL Act.</p><p><strong>70.14</strong> Entitlement</p><p>At any time after completing 7 years of Continuous employment with one Employer, an Employee is entitled to an amount of long service leave on ordinary pay equal to 1/60th of the Employee&#39;s total period of Continuous employment less any period of long service leave taken during that period.</p><p><strong>70.15</strong> Taking of leave</p><p><strong>(a)</strong> When leave is to be taken</p><p>In accordance with section 18(2) of the LSL Act, an Employer must grant an Employee&#39;s request to take long service leave as soon as practicable after receiving the request unless the Employer has reasonable business grounds for refusing the request.</p><p><strong>(b)</strong> How leave is to be taken</p><p>In accordance with section 18(1) of the LSL Act, an Employee may request to take long service leave for a period of not less than 1 day.</p><p><strong>(c)</strong> Long service leave in advance</p><p><strong>(i)</strong> Subject otherwise to this Part 3 and in accordance with section 8(1) of the LSL Act, an Employer may agree to a casual Registered Nurse or casual Registered Midwife taking long service leave prior to them completing 7 years of Continuous employment and at any time before they become entitled to long service leave.</p><p><strong>(ii)</strong> If an Employee takes long service leave in advance and the Employee&#39;s employment ends before the entitlement to the leave would otherwise have accrued:</p><p><strong>(A)</strong> the amount paid for the proportion of leave which the Employee will not become entitled becomes an amount owed by the Employee to the Employer;</p><p><strong>(B)</strong> the Employer may deduct this amount from any payment owed to the Employee as a result of the ending of employment; and</p><p><strong>(C)</strong> the relevant period of service will not count as a period in respect of which long service leave has already been taken (or paid in lieu) for the purpose of subclause 70.5(b) above (Periods that count towards Continuous Service).</p><p><strong>(d)</strong> Flexible taking of leave: double leave at half pay</p><p><strong>(i)</strong> An Employee may request an Employee to take double the period of long service leave at half pay.</p><p><strong>(ii)</strong> An Employer must grant such a request unless:</p><p><strong>(A)</strong> granting the request would result in an additional cost to the Employer; or</p><p><strong>(B)</strong> the Employer otherwise has reasonable business grounds for refusing the request.</p><p><strong>(iii)</strong> Employees should seek independent advice regarding the taxation and superannuation implications of seeking payment under this subclause 70.15(d). The Employer will not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>(iv)</strong> The Employer, if requested by the Employee, will provide information as to the amount of tax the Employer intends to deduct where payment of long service leave is sought under this subclause.</p><p><strong>70.16</strong> Payment on termination of employment</p><p><strong>(a)</strong> Basic entitlement at termination of employment</p><p>An Employee with seven or more years of Continuous employment is entitled to payment in lieu of untaken long service leave upon termination of employment, calculated at 1/60th of the period of Continuous employment.</p><p><strong>(b)</strong> Payment in lieu of long service leave on the death of an Employee</p><p>Where an Employee covered by this part has completed at least seven years’ Continuous employment and dies while still in the employ of the Employer, payment in lieu of long service leave will be made to the Employee’s personal representative equal to that in subclause 70.16(a) above.</p><p><strong>70.17</strong> Public holidays &amp; Annual leave</p><p>Long service leave does not include any public holiday occurring, or annual leave taken, during the period when the long service leave is taken.</p><p><strong>70.18</strong> No entitlement arising for periods of leave already taken</p><p>For the removal of doubt, no entitlement to long service leave (or payment in lieu) arises in respect of Continuous employment for which long service leave has already been taken or payment in lieu of leave has been received.</p><p><strong>70.19</strong> Other terms and conditions necessary for this Part</p><p>Any other term or condition necessary for the operation of this Part shall be in accordance with the applicable term or condition in the LSL Act.</p><p>Part 4 - Common conditions applicable to all Employees</p><p><strong>70.20</strong> Payment for period of leave</p><p><strong>(a)</strong> Payment will be made in one of the following ways:</p><p><strong>(i)</strong> in full advance when the Employee commences their leave;</p><p><strong>(ii)</strong> at the same time as payment would have been made if the Employee had remained on duty; or</p><p><strong>(iii)</strong> in any other way agreed between the Employer and the Employee.</p><p><strong>(b)</strong> Where an Employee has been paid in advance, and an increase occurs in the ordinary time rate of pay during the period of long service leave taken, the Employee will be entitled to receive payment of the amount of any increase in pay at the completion of such leave.</p><p><strong>70.21</strong> Proof of sufficient aggregate of service</p><p>The onus of proving a sufficient aggregate of service to support a claim for any long service leave entitlement will at all times rest upon the Employee concerned. A Certificate of Service in accordance with <a href="/eba/ebas/nurses-midwives/appendices/06-template-certificate-of-service.html">Appendix 6</a> will constitute acceptable proof.</p><p><strong>70.22</strong> Records</p><p>The Employer will keep a long service leave record for each Employee, containing particulars of service, leave taken and payments made.</p><p><strong>70.23</strong> Transfer of business</p><p>Where a Transfer of Business occurs, an Employee who worked with the old Employer and who continues in the service of the new Employer will be entitled to count their service with the old Employer as service with the new Employer for the purposes of this clause.</p><p><strong>70.24</strong> Concurrent Service</p><p><strong>(a)</strong> Subject to subclause (b), concurrent service with two or more Employers remains separate and distinct.</p><p><strong>(b)</strong> If an Award-entitled Employee transfers from an Employer (the first Employer) to a new Employer (the new Employer) as an Award-entitled Employee, but retains concurrent employment with the first Employer as a casual Employee, then the Employee&#39;s service with the first Employer may transfer to the new Employer (despite the Employee remaining employed with the first Employer), if:</p><p><strong>(i)</strong> the Employee does not have an entitlement to take long service leave under subclause 70.4(a);</p><p><strong>(ii)</strong> the Employee has not already taken or been paid in lieu of long service leave in respect of the relevant period; and</p><p><strong>(iii)</strong> either:</p><p><strong>(A)</strong> the Employee transfers their entitlement to the new Employer in accordance with subclause 70.8(c) (Election for payment of entitlement or transfer of entitlement at termination); or</p><p><strong>(B)</strong> the second Employer otherwise confirms in writing to the first Employer that the period of service has been so recognised (e.g. in accordance with <a href="/eba/ebas/nurses-midwives/appendices/06-template-certificate-of-service.html">Appendix 6</a>). For the removal of doubt, where the second Employer recognises the Employee&#39;s service with the first Employer, it must provide written notification of its determination to the first Employer.</p><p><strong>(c)</strong> If an Award-entitled Employee&#39;s long service leave entitlement is transferred in accordance with subclause 70.24(b):</p><p><strong>(i)</strong> the first Employer will no longer be liable for the service, and the long service leave liability for the service as an Award-entitled Employee with the first Employer will transfer to the new Employer;</p><p><strong>(v)</strong> any casual service that occurs with the first Employer after the transfer referred to in subclause 70.24(b) above will be considered separate and distinct service commencing from when the Employee ceased being an Award-entitled Employee with the first Employer, provided that:</p><p><strong>(A)</strong> the qualifying period required to manifest an entitlement to long service leave with the First Employer does not reset (that is, the Employee&#39;s prior service with the first Employer can be counted when calculating any future entitlement to long service leave with the first Employer);</p><p><strong>(B)</strong> no benefit to long service leave will arise with the first Employer in respect of the prior period of employment with the first Employer; and</p><p><strong>(C)</strong> the Employee&#39;s prior service with the first Employer is to be disregarded when calculating the Employee&#39;s normal weekly hours with the first Employer (e.g. for the purpose of sections 16 and 17 of the LSL Act).</p><p><strong>(ii)</strong> If the Employee is not entitled to transfer their service as an Award- entitled Employee from the first Employer to the new Employer, or does not take the steps required in subclause 70.24(b), the first Employer will, where applicable, make payment in lieu of long service leave for the Continuous Service with the first Employer upon ceasing permanent employment with the first Employer (under subclause 70.8(b) - Basic entitlement at termination of employment).</p><p>Example 1: An Award-entitled Employee is employed at the same time by Employer A, and Employer B. The Award-entitled Employee accrues service towards long service leave at each of Employer A and Employer B. If the Award-entitled Employee had been employed by Employer A for 11 years and Employer B for 6 years, the Award-entitled Employee can take LSL from Employer A, but would need to continue working at Employer B until sufficient Continuous Service had accrued. If the Award-entitled Employee resigned from both Employer A and Employer B, and went to work for Employer C, the Award-entitled Employee could:</p><p><strong>(a)</strong> transfer the 6 years&#39; service with Employer B to Employer C; and</p><p><strong>(b)</strong> have the accrued LSL from the 11 years&#39; service with Employer A paid out in lieu on termination. Example 2: An Award-entitled Employee has worked for Employer A for 6 years. On 1 June 2021, the Employee commences employment with Employer B as an Award-entitled Employee. To take up this opportunity, the Employee ceases permanent employment with Employer A. However, the Employee commences a casual employment relationship with Employer A within 12 weeks after resigning from their permanent position with Employer A. The Employee:</p><p><strong>(a)</strong> could transfer the 6 years&#39; service with Employer A to Employer B, and would be eligible to take LSL with Employer B once sufficient Continuous Service had accrued (taking into account the transferred service); and</p><p><strong>(b)</strong> could take LSL on a pro rata basis with Employer A after sufficient Continuous Service had accrued, save that no entitlement would arise in respect of the prior 6 years&#39; service that has been transferred to Employer B.</p><p><strong>70.25</strong> Savings</p><p><strong>(a)</strong> No Employee shall suffer any detriment as a result of the operation of this clause to their entitlement to long service leave existing immediately prior to the coming into force of this clause.</p><p>Plain language terms: LSL, long service, LSL entitlement.</p>',202)])])}const u=t(a,[["render",i]]);export{d as __pageData,u as default};
